sql:
SELECT dalys_percent
FROM health_statistics
WHERE year = 2020;

SELECT hs.data_source, hs.year, hs.dalys_percent, hs.confidence_level, hs.last_updated, hs.version 
FROM health_statistics hs
WHERE hs.cause_id = 0;

SELECT l.region, l.country, hs.dalys_percent
FROM health_statistics hs
JOIN locations l ON hs.location_id = l.location_id;

external_knowledge:
- 'Early '90s' refers to the year 1990;
- 'Health issues' refer to the causes of DALYs;
- 'DALYs percentages' are the average DALYs percentages for each cause and sex.

sql:
SELECT cause_name 
FROM causes 
WHERE cause_id = 1;

SELECT cause_name
FROM causes
WHERE prevalence > (
    SELECT AVG(prevalence)
    FROM causes
);

external_knowledge:
- 'moderate health issues' refers to DALYs percentage between 5% and 10%;
- 'young women' indicates age group 3 and sex_id 2;
- 'earliest recorded year' corresponds to year 1;
- 'latest data' implies is_current = 1.

sql:
SELECT age_id, AVG(dalys_percent) AS average_dalys_percent
FROM health_statistics
GROUP BY age_id;

SELECT COUNT(stat_id) AS num_entries
FROM health_statistics
WHERE last_updated LIKE '%1990%';

SELECT dalys_percent
FROM health_statistics
WHERE cause_id = 1 AND sex_id = 0;

SELECT stat_id, location_id, sex_id, age_id, cause_id, year, dalys_percent, confidence_level, data_source, last_updated, version, is_current
FROM health_statistics
WHERE stat_id = 1;

SELECT cause_name 
FROM causes 
WHERE category = 'Non-communicable';

SELECT HS.*, L.location_name 
FROM health_statistics HS
JOIN locations L ON HS.location_id = L.location_id;
